358→    #[test]
359→    fn same_branches_different_returns_same_class() {
360→        let path = vec![make_branch(0, true), make_branch(1, false)];
361→        let executions = vec![
362→            (vec![json!(5)], make_result(Some(json!("five")), path.clone())),
363→            (vec![json!(7)], make_result(Some(json!("seven")), path.clone())),
364→            (vec![json!(3)], make_result(Some(json!("three")), path)),
365→        ];
366→
367→        let classes = group_into_classes(&executions);
368→        assert_eq!(classes.len(), 1, "all should be in one class");
369→        assert_eq!(classes[0].all_inputs.len(), 3);
370→    }
