619→    #[test]
620→    fn precondition_round_trips() {
621→        let preconditions = vec![
622→            Precondition::AllPositive { param_index: 0 },
623→            Precondition::AllNegative { param_index: 1 },
624→            Precondition::AllZero { param_index: 2 },
625→            Precondition::AllEqual {
626→                param_index: 0,
627→                value: json!("test"),
628→            },
629→            Precondition::SameType {
630→                param_index: 0,
631→                type_name: "number".to_string(),
632→            },
633→        ];
634→        for p in &preconditions {
635→            let json = serde_json::to_string(p).expect("serialize");
